mapper.select:
SELECT YYYY, SEL_CODE, SITE as SITE_ORG, CASE WHEN SITE='HQ' Then '본사' WHEN SITE='VN' then 'VINA' else site end as SITE, MAT_CODE as MAT_CODE, MAT_DESC as MAT_DESC, EXPEN_SEL, [SIZE], MAT_CLASS, '' AS GUBUN FROM DOI_MATERIAL_MAST where 1=1
and yyyy = #{yyyy}
and site = #{site}
ORDER BY MAT_CODE

mapper.insert:
INSERT INTO DOI_MATERIAL_MAST
(
YYYY
, SEL_CODE
, SITE
, MAT_CODE
, MAT_DESC
, EXPEN_SEL
, [SIZE]
, MAT_CLASS
, GUBUN
)
VALUES
(
#{yyyy}
, #{selCode}
, CASE WHEN #{site}='본사' Then 'HQ'  WHEN #{site}='베트남' then 'VN' else left(#{site},2) end
, #{matCode}
, #{matDesc}
, #{expenSel}
, #{size}
, #{matClass}
, #{gubun}
);

mapper.delete:
DELETE FROM DOI_MATERIAL_MAST
WHERE 1=1
and yyyy = #{yyyy}
and sel_code = #{selCode}
and site = #{siteOrg}
and mat_code = #{matCode}

mapper.update:
UPDATE DOI_MATERIAL_MAST
SET SEL_CODE = #{selCode}
,MAT_DESC = #{matDesc}
,EXPEN_SEL = #{expenSel}
,[SIZE] = #{size}
,MAT_CLASS = #{matClass}
,GUBUN = #{gubun}
WHERE 1=1
and yyyy = #{yyyy}
and site = #{siteOrg}
and mat_code = #{matCode}
;
